-- ---------------------------------------------------------- Tabel structuur voor tabel bericht_tabel-- --------------------------------------------------------DROP TABLE IF EXISTS bericht_tabel;CREATE TABLE IF NOT EXISTS bericht_tabel (bericht_id int(10) NOT NULL default '0',persoon_id int(10) NOT NULL default '0',sender_id int(10) NOT NULL default '0',sender_naam varchar(30) NOT NULL default '0',datum date NOT NULL default '0000-00-00',tijd time default NULL,-- soort is till now email later smssoort varchar(8) default 'email',geziencheck tinyint(3) NOT NULL default '0',smscheck tinyint(3) NOT NULL default '0',berichtitel varchar(50) default NULL,aanvullingdoormij varchar(160) default NULL,berichttxt blob NOT NULL, PRIMARY KEY (bericht_id),KEY persoon_id (persoon_id)) TYPE=MyISAM AUTO_INCREMENT=100 ;-- Gegevens worden uitgevoerd voor tabel bericht_tabel
